def is_balanced(expr):
    stack = []
    for char in expr:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack:
                return False # Underflow means extra ')'
            stack.pop()
    return len(stack) == 0 # Balance check at end
